#!/usr/bin/env python3
import argparse
import importlib.util
import json
import shutil
import subprocess
from datetime import datetime, timedelta, timezone
from pathlib import Path

try:
    from scripts.project_repository_identity import inspect_repository_identity
except ModuleNotFoundError:
    from project_repository_identity import inspect_repository_identity


REQUIRED_PROJECT_PATHS = [
    ".moduflow/config.json",
    ".moduflow/state.json",
]

REQUIRED_PROFILE_PATHS = [
    ".moduflow/project-profile.md",
    ".moduflow/environments.json",
    ".moduflow/integrations.json",
]

REQUIRED_KNOWLEDGE_PATHS = [
    "knowledge",
    "knowledge/index.md",
    "knowledge/decisions",
    "knowledge/benchmarks",
    "knowledge/reports",
    "knowledge/research",
    "knowledge/data-notes",
    "knowledge/references",
]

REQUIRED_MEMORY_PATHS = [
    "memory",
    "memory/index.md",
    "memory/deliverables",
    "memory/decisions",
    "memory/evidence",
    "memory/meetings",
    "memory/releases",
    "memory/notes",
    "memory/references",
]

REQUIRED_WORKFLOW_PATHS = [
    "workflow/review-gates.md",
    "workflow/approval-policy.md",
    "workflow/release-policy.md",
    "workflow/handoff.md",
    "workflow/risks.md",
]

CANDIDATE_PATHS = {
    "issues": ["issues", "docs/issues", "planning/issues", ".github/ISSUE_TEMPLATE"],
    "specs": ["specs", "docs/specs", "docs/prd", "prd", "requirements"],
    "workspace": ["workspace", "planning", "docs/planning", "product"],
    "reports": ["reports", "docs/reports"],
    "benchmarks": ["benchmarks", "benchmark", "docs/benchmarks"],
    "research": ["research", "docs/research"],
    "decisions": ["decisions", "docs/decisions", "adr", "docs/adr"],
    "data_notes": ["data-notes", "data_notes", "docs/data-notes", "analytics"],
}


def load_project_validator():
    path = Path(__file__).resolve().parent / "validate_project_artifacts.py"
    spec = importlib.util.spec_from_file_location("validate_project_artifacts", path)
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


def load_project_loop():
    path = Path(__file__).resolve().parent / "project_loop.py"
    spec = importlib.util.spec_from_file_location("project_loop", path)
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


def load_project_memory():
    path = Path(__file__).resolve().parent / "project_memory.py"
    spec = importlib.util.spec_from_file_location("project_memory", path)
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


def load_project_lifecycle():
    path = Path(__file__).resolve().parent / "project_lifecycle.py"
    spec = importlib.util.spec_from_file_location("project_lifecycle", path)
    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)
    return module


def run(args, cwd):
    try:
        result = subprocess.run(
            args,
            cwd=cwd,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
        )
    except FileNotFoundError:
        return None
    return result


def read_config_paths(root):
    config_path = root / ".moduflow" / "config.json"
    if not config_path.exists():
        return {}
    try:
        config = json.loads(config_path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    return config.get("paths", {}) if isinstance(config.get("paths", {}), dict) else {}


def project_paths(root):
    paths = read_config_paths(root)
    issues = paths.get("issues", "issues")
    specs = paths.get("specs", "specs")
    workspace = paths.get("workspace", "workspace")
    return REQUIRED_PROJECT_PATHS + [
        issues,
        specs,
        f"{workspace}/inbox.md",
        f"{workspace}/opportunities.md",
        f"{workspace}/roadmap.md",
        f"{workspace}/dashboard.md",
    ]


def git_root(path):
    result = run(["git", "rev-parse", "--show-toplevel"], path)
    if result and result.returncode == 0:
        return Path(result.stdout.strip())
    return None


def git_remote(path):
    result = run(["git", "remote", "get-url", "origin"], path)
    if result and result.returncode == 0:
        return result.stdout.strip()
    return None


def current_branch(path):
    result = run(["git", "rev-parse", "--abbrev-ref", "HEAD"], path)
    if result and result.returncode == 0:
        return result.stdout.strip()
    return None


def local_project_root(path):
    current = Path(path).resolve()
    if current.is_file():
        current = current.parent
    for candidate in [current, *current.parents]:
        if (candidate / ".moduflow" / "config.json").exists():
            return candidate
    return current


def gh_auth_status(path):
    if shutil.which("gh") is None:
        return {"available": False, "authenticated": False, "detail": "gh not found"}
    result = run(["gh", "auth", "status"], path)
    if result is None:
        return {"available": False, "authenticated": False, "detail": "gh not found"}
    detail = (result.stdout + result.stderr).strip()
    return {
        "available": True,
        "authenticated": result.returncode == 0,
        "detail": detail.splitlines()[0] if detail else "",
    }


def missing_project_paths(root):
    missing = []
    for relative in project_paths(root):
        if not (root / relative).exists():
            missing.append(relative)
    return missing


def missing_profile_paths(root):
    missing = []
    for relative in REQUIRED_PROFILE_PATHS:
        if not (root / relative).exists():
            missing.append(relative)
    return missing


def missing_knowledge_paths(root):
    missing = []
    for relative in REQUIRED_KNOWLEDGE_PATHS:
        if not (root / relative).exists():
            missing.append(relative)
    return missing


def missing_memory_paths(root):
    missing = []
    for relative in REQUIRED_MEMORY_PATHS:
        if not (root / relative).exists():
            missing.append(relative)
    return missing


def missing_workflow_paths(root):
    missing = []
    for relative in REQUIRED_WORKFLOW_PATHS:
        if not (root / relative).exists():
            missing.append(relative)
    return missing


def discover_candidate_paths(root):
    candidates = {}
    for artifact_type, relative_paths in CANDIDATE_PATHS.items():
        matches = []
        for relative in relative_paths:
            if (root / relative).exists():
                matches.append(relative)
        if matches:
            candidates[artifact_type] = matches
    return candidates


def recommended_migration_mode(missing, candidates):
    if not missing:
        return None
    if candidates:
        return "mapped"
    return "overlay"


def detect_mode(root):
    manifest_path = root / ".claude-plugin" / "plugin.json"
    if manifest_path.exists() and (root / "vendor.lock.json").exists():
        try:
            data = json.loads(manifest_path.read_text(encoding="utf-8"))
            if data.get("name") == "moduflow":
                return "dogfooding"
        except Exception:
            pass

    legacy_dirs = ["commands", "skills", "scripts", "templates"]
    for d in legacy_dirs:
        dir_path = root / d
        if dir_path.is_dir() and any(dir_path.iterdir()):
            return "heavy"

    return "lightweight"


def mode_guidance(mode):
    guidance = {
        "lightweight": {
            "label": "가벼운 프로젝트 설정",
            "message": "프로젝트 설정이 가볍고 정상입니다.",
            "details": "commands, scripts, skills, templates 같은 도구 폴더는 플러그인에 남고 프로젝트에는 PM 산출물과 상태만 있습니다.",
            "action": "product:status",
        },
        "dogfooding": {
            "label": "모두플로 도구 저장소",
            "message": "모두플로 도구 저장소라 폴더가 많은 것이 정상입니다.",
            "details": "commands, scripts, skills, templates, adapters, vendor 같은 내부 개발/런타임 폴더가 이 저장소에 함께 있습니다.",
            "action": "product:status",
        },
        "heavy": {
            "label": "정리 권장 프로젝트 설정",
            "message": "프로젝트 안에 도구 폴더가 있어 정리를 권장합니다.",
            "details": "normal target projects should keep PM artifacts and state only; move commands, scripts, skills, and templates back to the ModuFlow plugin/source package.",
            "action": "product:migrate --mode overlay",
        },
    }
    return guidance.get(
        mode,
        {
            "label": "프로젝트 설정 확인 필요",
            "message": "프로젝트 설정 상태를 확인해야 합니다.",
            "details": "Run product:doctor for diagnostics.",
            "action": "product:doctor",
        },
    )


def skipped_preflight_status():
    return {
        "available": None,
        "authenticated": None,
        "detail": "preflight skipped",
    }


def installed_plugin_staleness(project_root, home=None):
    """Soft check: is the installed ModuFlow plugin copy behind this repo's version?"""
    home = Path(home) if home is not None else Path.home()
    empty = {"checked": False, "stale": [], "recommendations": []}

    plugin_manifest_path = Path(project_root) / ".claude-plugin" / "plugin.json"
    try:
        manifest = json.loads(plugin_manifest_path.read_text(encoding="utf-8"))
    except Exception:
        return empty
    # Only the moduflow source repo's own version is comparable to the
    # installed moduflow copies — any other plugin's manifest must not
    # produce a spurious staleness warning.
    if manifest.get("name") != "moduflow":
        return empty
    repo_version = manifest.get("version")
    if not repo_version:
        return empty

    stale = []
    recommendations = []

    installed_plugins_path = home / ".claude" / "plugins" / "installed_plugins.json"
    try:
        if installed_plugins_path.exists():
            data = json.loads(installed_plugins_path.read_text(encoding="utf-8"))
            entries = data.get("plugins", {}).get("moduflow@moduflow", [])
            for entry in entries:
                installed_version = entry.get("version")
                if installed_version and installed_version != repo_version:
                    stale.append(
                        {"host": "claude-code", "installed": installed_version, "repo": repo_version}
                    )
                    recommendations.append(
                        "claude plugin marketplace update moduflow && claude plugin update moduflow@moduflow"
                    )
    except Exception:
        pass

    codex_cache_dir = home / ".codex" / "plugins" / "cache" / "personal" / "moduflow"
    try:
        if codex_cache_dir.exists():
            versions = [d.name for d in codex_cache_dir.iterdir() if d.is_dir()]
            if versions and not any(name.split("+")[0] == repo_version for name in versions):

                def _numeric_base(name):
                    try:
                        return tuple(int(part) for part in name.split("+")[0].split("."))
                    except ValueError:
                        return (-1,)

                newest = max(versions, key=_numeric_base)
                stale.append({"host": "codex", "installed": newest, "repo": repo_version})
                recommendations.append("python3 scripts/register_codex_personal_marketplace.py .")
    except Exception:
        pass

    return {"checked": True, "stale": stale, "recommendations": recommendations}


def check_hook_log(root):
    """Parse .moduflow/logs/hooks.log and return recent warnings.

    Format: <iso-ts> <hook> <level:warn|error> <message>
    Returns: list of warning dicts with hook, level, timestamp, message
    Filters: last 7 days, capped at 20 most recent

    Absent file or zero recent entries: return empty list (silent)
    Unparseable lines: include with a malformed note
    """
    warnings = []
    log_path = root / ".moduflow" / "logs" / "hooks.log"

    if not log_path.exists():
        return warnings

    try:
        content = log_path.read_text(encoding="utf-8")
    except Exception:
        return warnings

    if not content.strip():
        return warnings

    # Calculate cutoff: last 7 days
    now = datetime.now(timezone.utc)
    cutoff = now - timedelta(days=7)

    lines = content.splitlines()
    recent_entries = []

    for line in lines:
        if not line.strip():
            continue

        parts = line.split(None, 3)  # Split on whitespace, max 4 parts

        if len(parts) < 4:
            # Malformed line: include with a note
            recent_entries.append({
                "hook": "unknown",
                "level": "warn",
                "timestamp": None,
                "message": f"malformed hook log entry: {line}",
                "malformed": True,
            })
            continue

        iso_ts_str, hook, level, message = parts

        # Try to parse ISO timestamp
        try:
            # Handle both with/without microseconds
            if "." in iso_ts_str:
                ts = datetime.fromisoformat(iso_ts_str.replace("Z", "+00:00"))
            else:
                ts = datetime.fromisoformat(iso_ts_str.replace("Z", "+00:00"))
        except (ValueError, AttributeError):
            # Unparseable timestamp: include with a note
            recent_entries.append({
                "hook": hook,
                "level": level,
                "timestamp": None,
                "message": message,
                "malformed": True,
                "note": f"unparseable timestamp: {iso_ts_str}",
            })
            continue

        # Check if within 7-day window
        if ts >= cutoff:
            recent_entries.append({
                "hook": hook,
                "level": level,
                "timestamp": iso_ts_str,
                "message": message,
            })

    # Sort by timestamp descending (most recent first) and cap at 20
    recent_entries.sort(
        key=lambda x: x.get("timestamp") or "",
        reverse=True
    )

    # Return the 20 most recent
    return recent_entries[:20]


def inspect_project(path, include_preflight=True):
    requested = Path(path).resolve()
    if include_preflight:
        detected_git_root = git_root(requested)
        project_root = detected_git_root or requested
        remote = git_remote(project_root) if detected_git_root else None
        gh_status = gh_auth_status(project_root)
        repository_identity = inspect_repository_identity(project_root)
    else:
        detected_git_root = None
        project_root = local_project_root(requested)
        remote = None
        gh_status = skipped_preflight_status()
        repository_identity = None

    missing = missing_project_paths(project_root)
    missing_profile = missing_profile_paths(project_root)
    missing_knowledge = missing_knowledge_paths(project_root)
    missing_memory = missing_memory_paths(project_root)
    try:
        isolated_memory = load_project_memory().isolated_memory_entries(project_root) if not missing_memory else []
    except Exception:
        isolated_memory = []
    try:
        lifecycle_drift = load_project_lifecycle().lifecycle_drift(project_root)
    except Exception:
        lifecycle_drift = []
    try:
        plugin_staleness = installed_plugin_staleness(project_root)
    except Exception:
        plugin_staleness = {"checked": False, "stale": [], "recommendations": []}
    try:
        hook_log_warnings = check_hook_log(project_root)
    except Exception:
        hook_log_warnings = []
    missing_workflow = missing_workflow_paths(project_root)
    candidates = discover_candidate_paths(project_root)
    migration_mode = recommended_migration_mode(missing, candidates)
    project_loop = load_project_loop()
    project_validator = load_project_validator()
    schema_gates = project_validator.validate_project(project_root)
    loop_errors = project_loop.validate_loop_state(project_root)
    loop_state_exists = (project_root / "workspace" / "loop-state.json").exists()
    loop_state = project_loop.load_loop_state(project_root) if loop_state_exists else None
    git_binding = loop_state.get("git_binding") if loop_state else None
    branch = current_branch(project_root) if include_preflight and detected_git_root else None

    mode = detect_mode(project_root)
    result = {
        "requested_path": str(requested),
        "project_root": str(project_root),
        "mode": mode,
        "mode_guidance": mode_guidance(mode),
        "preflight": {
            "enabled": include_preflight,
            "skipped": [] if include_preflight else ["git", "github_cli", "repository_identity"],
        },
        "git": {
            "is_repo": detected_git_root is not None,
            "root": str(detected_git_root) if detected_git_root else None,
            "origin": remote,
            "branch": branch,
        },
        "git_binding": {
            "declared": git_binding,
            "errors": loop_errors,
        },
        "github_cli": gh_status,
        "repository_identity": repository_identity,
        "moduflow": {
            "initialized": not missing,
            "missing": missing,
        },
        "migration": {
            "recommended_mode": migration_mode,
            "candidates": candidates,
        },
        "profile": {
            "initialized": not missing_profile,
            "missing": missing_profile,
        },
        "knowledge": {
            "initialized": not missing_knowledge,
            "missing": missing_knowledge,
        },
        "memory": {
            "initialized": not missing_memory,
            "missing": missing_memory,
            "isolated": isolated_memory,  # soft hint only — never affects exit code
        },
        "lifecycle": {
            "drift": lifecycle_drift,  # 048: issue files vs state.json/dashboard
        },
        "installed_plugin": plugin_staleness,  # soft hint only — never affects exit code
        "workflow": {
            "initialized": not missing_workflow,
            "missing": missing_workflow,
        },
        "loop": {
            "initialized": loop_state_exists,
            "errors": loop_errors,
        },
        "schema_gates": {
            "valid": schema_gates.get("valid", False),
            "errors": schema_gates.get("errors", []),
            "warnings": schema_gates.get("warnings", []),
        },
        "hooks": {
            "warnings": hook_log_warnings,
        },
        "recommendation": [],
    }

    if not include_preflight:
        result["recommendation"].append("Run product:doctor with preflight when GitHub sync or Git state checks are needed.")
    elif not result["git"]["is_repo"]:
        result["recommendation"].append("Run git init or choose an existing Git project before GitHub Spec Kit-style execution.")
    elif not remote:
        result["recommendation"].append("Add a GitHub origin if issues, PRs, and releases should sync with GitHub.")

    if include_preflight and not gh_status["available"]:
        result["recommendation"].append("Install GitHub CLI if GitHub issue/PR sync is needed.")
    elif include_preflight and not gh_status["authenticated"]:
        result["recommendation"].append("Run gh auth login if GitHub issue/PR sync is needed.")

    if missing:
        if migration_mode == "mapped":
            result["recommendation"].append("Run product:migrate --mode mapped to plan a non-destructive migration.")
        else:
            result["recommendation"].append("Run product:migrate --mode overlay to add ModuFlow metadata without moving existing files.")
        result["recommendation"].append("Run product:start after migration planning if this is a new project.")
    else:
        result["recommendation"].append("Run product:status to inspect current work.")

    if missing_profile:
        result["recommendation"].append("Run product:profile --write to create project profile metadata.")

    if missing_knowledge:
        result["recommendation"].append("Run product:knowledge --write to create knowledge evidence structure.")

    if missing_memory:
        result["recommendation"].append("Run product:memory --write to create portable project memory structure.")

    if missing_workflow:
        result["recommendation"].append("Run product:handoff --write to create team workflow artifacts.")

    if isolated_memory:
        result["recommendation"].append(
            f"hint: {len(isolated_memory)} isolated memory entries (no relationships or issue_id) — "
            "run product:memory --list-ids and link real nodes (043). Informational, not required."
        )

    if lifecycle_drift:
        result["recommendation"].append(
            f"lifecycle drift: {len(lifecycle_drift)} disagreement(s) between issue files and "
            "derived views — run `python3 scripts/project_lifecycle.py . --sync` (048)."
        )

    if loop_state and branch and branch not in {"main", "master"}:
        active_issue_id = loop_state.get("active_issue_id")
        if active_issue_id and not project_loop.branch_matches_issue(branch, active_issue_id):
            result["recommendation"].append("Current branch does not match active issue; switch branches or update workspace/loop-state.json git_binding.")

    if loop_errors:
        result["recommendation"].append("Run product:loop or product:doctor after fixing loop-state references.")

    if schema_gates.get("errors"):
        result["recommendation"].append("schema gate failed; fix linked artifacts, state drift, or next_command before release.")

    if hook_log_warnings:
        result["recommendation"].append(
            f"hook health: {len(hook_log_warnings)} lifecycle hook event(s) logged in last 7 days (warnings/errors) — "
            "review .moduflow/logs/hooks.log for details."
        )

    result["recommendation"].extend(plugin_staleness["recommendations"])

    return result


def main():
    parser = argparse.ArgumentParser(description="Inspect ModuFlow project setup.")
    parser.add_argument("project_path", nargs="?", default=".")
    parser.add_argument(
        "--no-preflight",
        action="store_true",
        help="Skip Git and GitHub CLI preflight checks for local-only validation.",
    )
    args = parser.parse_args()
    result = inspect_project(args.project_path, include_preflight=not args.no_preflight)
    print(json.dumps(result, ensure_ascii=False, indent=2))
    moduflow = result.get("moduflow", {})
    # Gate: a project is healthy only when ModuFlow is initialized with no missing
    # required artifacts. Returning a real exit code makes project_doctor an
    # actual gate inside release_check instead of an always-pass no-op.
    return 0 if moduflow.get("initialized") and not moduflow.get("missing") else 1


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
import argparse
import json
import sys
from pathlib import Path

if __package__ in (None, ""):
    sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from scripts.project_sync import run_command
from scripts.project_repository_identity import (
    inspect_repository_identity,
    operation_decision,
)

PROBE_FILENAME = ".moduflow-write-probe"


def _default_probe_write(git_dir):
    """Attempt a non-destructive local Git write. Never touches index.lock."""
    probe_path = git_dir / PROBE_FILENAME
    try:
        probe_path.write_text("probe", encoding="utf-8")
        probe_path.unlink()
        return True, ""
    except OSError as exc:
        return False, f"local .git write failed: {exc}"


def _resolve_git_dir(root):
    """Return the directory Git uses for repository-local state."""
    git_entry = root / ".git"
    if not git_entry.exists():
        return None, "not a git repository (.git missing)"
    if git_entry.is_dir():
        return git_entry, ""

    try:
        marker = git_entry.read_text(encoding="utf-8").strip()
    except OSError as exc:
        return None, f"cannot read .git worktree pointer: {exc}"
    prefix = "gitdir:"
    if not marker.lower().startswith(prefix):
        return None, "invalid .git worktree pointer"
    target = marker[len(prefix) :].strip()
    if not target:
        return None, "invalid .git worktree pointer: missing gitdir"
    git_dir = Path(target)
    if not git_dir.is_absolute():
        git_dir = git_entry.parent / git_dir
    return git_dir.resolve(), ""


def _github_api_available(root, runner):
    result = runner(["gh", "auth", "status"], root)
    return result.returncode == 0


def check_commit_capability(root, runner=None, probe_write=None, operation="commit"):
    """Classify commit capability as local-git-write, github-api-commit, or blocked."""
    if runner is None:
        runner = run_command
    if probe_write is None:
        probe_write = _default_probe_write
    root = Path(root)
    identity = None

    if (root / ".moduflow" / "config.json").is_file():
        identity = inspect_repository_identity(root, runner=runner)
        decision = operation_decision(identity, operation)
        if not decision["allowed"]:
            reason = "; ".join(
                item.get("message", item.get("code", "identity denied"))
                for item in decision["reasons"]
            )
            return {
                "mode": "identity-blocked",
                "ok": False,
                "local_git_write": False,
                "github_api_available": False,
                "reason": reason,
                "recommendations": [
                    "Fix or explicitly migrate canonical repository identity before Git/GitHub writes."
                ],
                "repository_identity": decision,
            }

    git_dir, resolve_reason = _resolve_git_dir(root)

    if git_dir is None:
        local_ok, local_reason = False, resolve_reason
    else:
        local_ok, local_reason = probe_write(git_dir)

    if local_ok:
        return {
            "mode": "local-git-write",
            "ok": True,
            "local_git_write": True,
            "github_api_available": None,
            "reason": "",
            "recommendations": [],
        }

    if identity is not None:
        fallback_decision = operation_decision(identity, "github_api_commit")
        if not fallback_decision["allowed"]:
            return {
                "mode": "blocked",
                "ok": False,
                "local_git_write": False,
                "github_api_available": False,
                "reason": local_reason,
                "recommendations": [
                    "GitHub API fallback is unavailable because canonical repository "
                    "identity does not allow github_write."
                ],
                "repository_identity": fallback_decision,
            }

    github_ok = _github_api_available(root, runner)
    if github_ok:
        return {
            "mode": "github-api-commit",
            "ok": True,
            "local_git_write": False,
            "github_api_available": True,
            "reason": local_reason,
            "recommendations": [
                "Local Git write is blocked — use the GitHub API "
                "(gh api, or an MCP GitHub tool) to create/update the branch "
                "instead of local git add/commit/push.",
            ],
        }

    return {
        "mode": "blocked",
        "ok": False,
        "local_git_write": False,
        "github_api_available": False,
        "reason": local_reason,
        "recommendations": [
            "Neither local Git writes nor GitHub API access are available — "
            "ask the user to run the needed Git commands manually.",
        ],
    }


def main():
    parser = argparse.ArgumentParser(description="Classify local Git vs GitHub API commit capability.")
    parser.add_argument("root", nargs="?", default=".", help="Project root path")
    parser.add_argument("--operation", choices=["commit", "push"], default="commit")
    args = parser.parse_args()

    result = check_commit_capability(args.root, operation=args.operation)
    print(json.dumps(result, indent=2))
    return 0 if result["ok"] else 1


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Opt-in one-way sync of a git-file issue to a GitHub Issue (054).

`issues/<id>.md` stays canonical; the GitHub Issue is a synced projection with
a `moduflow:<status>` label. The GitHub issue URL is written back into the
issue file's `## Links` section, which is the create-vs-update discriminator.
"""
import argparse
import json
import re
import sys
from pathlib import Path

if __package__ in (None, ""):
    sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from scripts.project_sync import run_command
from scripts.project_lifecycle import _issue_status
from scripts.project_repository_identity import (
    IdentityConfigError,
    inspect_repository_identity,
    operation_decision,
    repository_from_github_artifact_url,
)

LABELS = {
    "backlog": "moduflow:backlog",
    "active": "moduflow:active",
    "done": "moduflow:done",
    "superseded": "moduflow:superseded",
}
LABEL_COLORS = {
    "backlog": "ededed",
    "active": "fbca04",
    "done": "0e8a16",
    "superseded": "6f42c1",
}
BODY_MARKER = "<!-- moduflow:issue-sync -->"

SSH_URL_RE = re.compile(r"^git@[^:/]+:([^/]+)/(.+?)(?:\.git)?/?$")
HTTPS_URL_RE = re.compile(r"^https://github\.com/([^/]+)/([^/]+?)(?:\.git)?/?$")
GITHUB_LINK_RE = re.compile(r"^-\s*GitHub:\s*(\S+)\s*$", re.MULTILINE)
ISSUE_NUMBER_RE = re.compile(r"/issues/(\d+)/?$")


def _parse_owner_repo(url):
    for pattern in (SSH_URL_RE, HTTPS_URL_RE):
        m = pattern.match((url or "").strip())
        if m:
            repo = m.group(2)
            # Reject nested paths early so the failure is a clear parse error
            # instead of an opaque gh error from "-R owner/nested/repo".
            if "/" in repo:
                return None
            return f"{m.group(1)}/{repo}"
    return None


def _github_sync_mode(root):
    config_path = Path(root) / ".moduflow" / "config.json"
    try:
        config = json.loads(config_path.read_text(encoding="utf-8"))
    except Exception:
        return None
    git_config = config.get("git")
    if not isinstance(git_config, dict):
        return None
    return git_config.get("github_sync")


def _links_section(text):
    lines = text.splitlines()
    start = next((i for i, line in enumerate(lines) if line.strip() == "## Links"), None)
    if start is None:
        return ""
    end = len(lines)
    for i in range(start + 1, len(lines)):
        if lines[i].startswith("## "):
            end = i
            break
    return "\n".join(lines[start + 1:end])


def _github_link(text):
    # The Links section is the only place the mapping is canonical — a stray
    # "- GitHub:" bullet elsewhere must not flip create into update.
    m = GITHUB_LINK_RE.search(_links_section(text))
    return m.group(1) if m else None


def _issue_title(text):
    for line in text.splitlines():
        if line.startswith("# "):
            heading = line[2:].strip()
            if ":" in heading:
                heading = heading.split(":", 1)[1].strip()
            return heading.strip("`").strip()
    return ""


def _outcome_section(text):
    lines = text.splitlines()
    collected = []
    in_outcome = False
    in_fence = False
    for line in lines:
        if line.strip() == "## Outcome":
            in_outcome = True
            continue
        if in_outcome:
            if line.lstrip().startswith("```"):
                in_fence = not in_fence
            # A "## " line inside a code fence is content, not a heading.
            if line.startswith("## ") and not in_fence:
                break
            collected.append(line)
    section = "\n".join(collected).strip()
    if section:
        return section
    # Fallback: first non-heading, non-blank paragraph.
    paragraph = []
    for line in lines:
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            if paragraph:
                break
            continue
        paragraph.append(stripped)
    return "\n".join(paragraph).strip()


def _issue_body(text, repo, issue_id):
    base = _outcome_section(text)
    return (
        f"{base}\n\n---\n"
        f"Canonical source: https://github.com/{repo}/blob/HEAD/issues/{issue_id}.md\n"
        f"{BODY_MARKER}"
    )


def _write_github_link(path, url):
    text = path.read_text(encoding="utf-8")
    lines = text.splitlines()
    link_line = f"- GitHub: {url}"

    links_idx = next((i for i, line in enumerate(lines) if line.strip() == "## Links"), None)

    # Replace an existing "- GitHub:" bullet inside Links instead of appending
    # a duplicate.
    if links_idx is not None:
        section_end = len(lines)
        for i in range(links_idx + 1, len(lines)):
            if lines[i].startswith("## "):
                section_end = i
                break
        for i in range(links_idx + 1, section_end):
            if GITHUB_LINK_RE.match(lines[i].strip()):
                lines[i] = link_line
                path.write_text("\n".join(lines) + "\n", encoding="utf-8")
                return

    if links_idx is None:
        section = ["## Links", "", link_line, ""]
        next_idx = next(
            (i for i, line in enumerate(lines) if line.strip() == "## Next Command"), None
        )
        if next_idx is None:
            if lines and lines[-1].strip():
                lines.append("")
            lines.extend(["## Links", "", link_line])
        else:
            lines[next_idx:next_idx] = section
    else:
        end = len(lines)
        for i in range(links_idx + 1, len(lines)):
            if lines[i].startswith("## "):
                end = i
                break
        insert = end
        while insert > links_idx + 1 and not lines[insert - 1].strip():
            insert -= 1
        lines.insert(insert, link_line)

    path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def _ensure_labels(runner, cwd, repo):
    result = runner(["gh", "label", "list", "-R", repo, "--json", "name"], cwd)
    if result.returncode != 0:
        return f"gh label list failed: {(result.stderr or '').strip()}"
    try:
        existing = {item.get("name") for item in json.loads(result.stdout or "[]")}
    except json.JSONDecodeError:
        existing = set()
    for status, name in LABELS.items():
        if name in existing:
            continue
        created = runner(
            ["gh", "label", "create", name, "-R", repo, "--color", LABEL_COLORS[status]], cwd
        )
        if created.returncode != 0:
            # "already exists" is success for this idempotent bootstrap — it
            # happens when `gh label list` output couldn't be parsed and we
            # conservatively retried creation.
            if "already exists" in (created.stderr or "").lower():
                continue
            return f"gh label create {name} failed: {(created.stderr or '').strip()}"
    return None


def _error(message, issue_id, repository_identity=None, reason_code=None):
    result = {"action": "error", "issue_id": issue_id, "error": message}
    if repository_identity is not None:
        result["repository_identity"] = repository_identity
    if reason_code is not None:
        result["reason_code"] = reason_code
    return result


def sync_issue(root, issue_id, runner=None):
    root = Path(root).resolve()

    mode = _github_sync_mode(root)
    if mode == "off":
        return {
            "action": "disabled",
            "issue_id": issue_id,
            "reason": "git.github_sync is 'off' in .moduflow/config.json",
        }

    runner = runner or run_command

    identity = inspect_repository_identity(root, runner=runner)
    decision = operation_decision(identity, "github_issue")
    if not decision["allowed"]:
        decision_codes = {reason["code"] for reason in decision["reasons"]}
        return _error(
            "canonical repository identity denied GitHub issue sync",
            issue_id,
            repository_identity=decision,
            reason_code=(
                "stale_artifact_repository"
                if "artifact_write_repository_mismatch" in decision_codes
                else None
            ),
        )
    canonical_repository = identity["expected"].get("repository", "")
    if not canonical_repository.startswith("github.com/"):
        return _error(
            "canonical GitHub repository is unavailable",
            issue_id,
            repository_identity=decision,
        )
    repo = canonical_repository[len("github.com/") :]

    issue_path = root / "issues" / f"{issue_id}.md"
    if not issue_path.is_file():
        return _error(f"issue file not found: {issue_path}", issue_id)
    text = issue_path.read_text(encoding="utf-8")

    status = _issue_status(text)
    label = LABELS[status]

    existing_url = _github_link(text)
    if existing_url:
        try:
            linked_repository = repository_from_github_artifact_url(existing_url)
        except IdentityConfigError:
            return _error(
                "existing GitHub issue URL is malformed",
                issue_id,
                repository_identity=decision,
                reason_code="artifact_repository_unverifiable",
            )
        if linked_repository != canonical_repository:
            return _error(
                "existing GitHub issue URL targets a non-canonical repository",
                issue_id,
                repository_identity=decision,
                reason_code="stale_artifact_repository",
            )

    label_error = _ensure_labels(runner, root, repo)
    if label_error:
        return _error(label_error, issue_id)

    if existing_url:
        number_match = ISSUE_NUMBER_RE.search(existing_url)
        if not number_match:
            return _error(f"could not parse issue number from URL: {existing_url}", issue_id)
        stale = [name for name in LABELS.values() if name != label]
        args = ["gh", "issue", "edit", number_match.group(1), "-R", repo, "--add-label", label]
        for name in stale:
            args.extend(["--remove-label", name])
        edited = runner(args, root)
        if edited.returncode != 0:
            return _error(f"gh issue edit failed: {(edited.stderr or '').strip()}", issue_id)
        return {"action": "updated", "issue_id": issue_id, "url": existing_url, "label": label}

    title = _issue_title(text)
    body = _issue_body(text, repo, issue_id)
    created = runner(
        ["gh", "issue", "create", "-R", repo, "--title", title, "--body", body, "--label", label],
        root,
    )
    if created.returncode != 0:
        return _error(f"gh issue create failed: {(created.stderr or '').strip()}", issue_id)
    stdout_lines = [line.strip() for line in (created.stdout or "").splitlines() if line.strip()]
    if not stdout_lines:
        return _error("gh issue create returned no URL", issue_id)
    url = stdout_lines[-1]
    _write_github_link(issue_path, url)
    return {"action": "created", "issue_id": issue_id, "url": url, "label": label}


def main():
    parser = argparse.ArgumentParser(
        description="Sync a git-file issue to a GitHub Issue (opt-in, one-way)."
    )
    parser.add_argument("project_path", nargs="?", default=".")
    parser.add_argument("--issue-id", required=True)
    parser.add_argument("--sync", action="store_true", help="Create or update the GitHub Issue.")
    args = parser.parse_args()
    if not args.sync:
        parser.error("--sync is required")
    result = sync_issue(args.project_path, args.issue_id)
    print(json.dumps(result, ensure_ascii=False, indent=2))
    return 1 if result.get("action") == "error" else 0


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
import argparse
import json
import re
from pathlib import Path

from scripts.project_repository_identity import (
    ALLOWED_LIFECYCLES,
    ALLOWED_PROVIDERS,
    IdentityConfigError,
    load_repository_identity,
    normalize_git_url,
)


IDENTITY_BLOCK_START = "<!-- moduflow:repository-identity:start -->"
IDENTITY_BLOCK_END = "<!-- moduflow:repository-identity:end -->"


PROFILE_FILES = {
    ".moduflow/project-profile.md": """# Project Profile

## Summary

- Project:
- Owner:
- Team:
- Status:

## Purpose

Describe what this project is responsible for and why it exists.

## Key Links

- Repository:
- Product docs:
- Design:
- Dashboard:
- Deployment:

## Operating Notes

- Primary workflow:
- Release cadence:
- Support channel:

## Sensitive Data Rules

- Do not store credentials, API keys, private keys, signed originals, seals, identity documents, or direct personal contact/payment identifiers in this repo.
- Store secret manager references or environment variable names instead of secret values.
""",
    ".moduflow/environments.json": {
        "schema": "moduflow.environments.v1",
        "environments": [
            {
                "name": "development",
                "url": "",
                "deploy_target": "",
                "data_source": "",
                "notes": "",
            },
            {
                "name": "staging",
                "url": "",
                "deploy_target": "",
                "data_source": "",
                "notes": "",
            },
            {
                "name": "production",
                "url": "",
                "deploy_target": "",
                "data_source": "",
                "notes": "",
            },
        ],
        "sensitive_data_policy": "Store references only. Do not store secret values.",
    },
    ".moduflow/integrations.json": {
        "schema": "moduflow.integrations.v1",
        "integrations": {
            "github": {
                "repository": "",
                "issues": "",
                "pull_requests": "",
            },
            "docs": {
                "primary": "",
                "design": "",
                "analytics": "",
            },
            "communication": {
                "slack_channel": "",
                "email_group": "",
            },
            "analytics": {
                "dashboard": "",
                "warehouse": "",
            },
        },
        "sensitive_data_policy": "Store links and labels only. Do not store credentials.",
    },
}


def render_content(content):
    if isinstance(content, str):
        return content
    return json.dumps(content, ensure_ascii=False, indent=2) + "\n"


def build_profile_plan(path, dry_run=True):
    project_root = Path(path).resolve()
    writes = []
    for relative in PROFILE_FILES:
        if not (project_root / relative).exists():
            writes.append(relative)
    return {
        "schema": "moduflow.profile-plan.v1",
        "project_root": str(project_root),
        "dry_run": dry_run,
        "writes": writes,
        "preserves_existing_files": True,
        "sensitive_data_policy": "Do not store credentials, secrets, signed originals, seals, identity documents, or direct personal contact/payment identifiers.",
    }


def write_if_missing(path, content):
    if path.exists():
        return False
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(render_content(content), encoding="utf-8")
    return True


def apply_profile_plan(plan):
    project_root = Path(plan["project_root"])
    written = []
    for relative, content in PROFILE_FILES.items():
        if write_if_missing(project_root / relative, content):
            written.append(relative)
    plan["written"] = written
    return plan


def _read_config(root):
    path = Path(root) / ".moduflow" / "config.json"
    if not path.is_file():
        return {"schema": "moduflow.config.v1", "git": {}}
    try:
        config = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        raise ValueError(".moduflow/config.json must contain valid JSON before profile write.") from exc
    if not isinstance(config, dict):
        raise ValueError(".moduflow/config.json must contain a JSON object.")
    return config


def _legacy_remote_candidate(config, provider):
    git_config = config.get("git")
    remote = git_config.get("remote") if isinstance(git_config, dict) else None
    if not isinstance(remote, str) or not remote.strip():
        return None
    try:
        return normalize_git_url(remote, provider)
    except IdentityConfigError:
        return None


def build_repository_identity_proposal(
    path,
    canonical_repository=None,
    provider=None,
    remote_name_hint=None,
    base_branch=None,
    lifecycle=None,
    local_only=False,
):
    """Build an explicit identity proposal without adopting observed state."""
    root = Path(path).resolve()
    config = _read_config(root)
    selected_provider = provider or "github"
    selected_base = base_branch or "main"
    selected_lifecycle = lifecycle or "active"

    if selected_provider not in ALLOWED_PROVIDERS:
        raise ValueError("provider must be github or generic")
    if selected_lifecycle not in ALLOWED_LIFECYCLES:
        raise ValueError("lifecycle must be active, read_only, or archived")
    if not isinstance(selected_base, str) or not selected_base.strip():
        raise ValueError("base_branch must be a non-empty string")

    existing = load_repository_identity(root)
    proposed_identity = None
    source = "none"
    if local_only:
        proposed_identity = {
            "mode": "local_only",
            "provider": selected_provider,
            "base_branch": selected_base.strip(),
            "lifecycle": selected_lifecycle,
        }
        source = "explicit_local_only"
    elif canonical_repository is not None:
        proposed_identity = {
            "mode": "remote",
            "provider": selected_provider,
            "canonical_repository": normalize_git_url(
                canonical_repository,
                selected_provider,
            ),
            "remote_name_hint": (remote_name_hint or "origin").strip(),
            "base_branch": selected_base.strip(),
            "lifecycle": selected_lifecycle,
        }
        if not proposed_identity["remote_name_hint"]:
            raise ValueError("remote_name_hint must be a non-empty string")
        source = "explicit_remote"
    elif existing["configured"]:
        proposed_identity = dict(existing["identity"])
        source = "existing_identity"

    legacy_candidate = _legacy_remote_candidate(config, selected_provider)
    return {
        "schema": "moduflow.repository-identity-proposal.v1",
        "project_root": str(root),
        "source": source,
        "requires_confirmation": proposed_identity is None and legacy_candidate is not None,
        "legacy_remote_candidate": legacy_candidate,
        "proposed_identity": proposed_identity,
        "writes": proposed_identity is not None,
    }


def render_repository_identity_projection(identity):
    lines = [
        IDENTITY_BLOCK_START,
        "## Repository Identity",
        "",
        f"- Mode: `{identity['mode']}`",
        f"- Provider: `{identity['provider']}`",
    ]
    if identity["mode"] == "remote":
        lines.extend(
            [
                f"- Canonical repository: `{identity['canonical_repository']}`",
                f"- Remote name hint: `{identity['remote_name_hint']}`",
            ]
        )
    lines.extend(
        [
            f"- Base branch: `{identity['base_branch']}`",
            f"- Lifecycle: `{identity['lifecycle']}`",
            IDENTITY_BLOCK_END,
        ]
    )
    return "\n".join(lines) + "\n"


def _project_profile_with_identity(existing, identity):
    block = render_repository_identity_projection(identity)
    pattern = re.compile(
        re.escape(IDENTITY_BLOCK_START)
        + r".*?"
        + re.escape(IDENTITY_BLOCK_END)
        + r"\n?",
        re.DOTALL,
    )
    if pattern.search(existing):
        return pattern.sub(block, existing, count=1)
    separator = "" if not existing else ("\n" if existing.endswith("\n") else "\n\n")
    return existing + separator + block


def apply_repository_identity_proposal(path, proposal):
    """Write one confirmed identity while preserving unrelated project content."""
    identity = proposal.get("proposed_identity")
    if not isinstance(identity, dict):
        raise ValueError("repository identity proposal requires explicit confirmation before write")

    root = Path(path).resolve()
    config_path = root / ".moduflow" / "config.json"
    profile_path = root / ".moduflow" / "project-profile.md"
    config = _read_config(root)
    git_config = config.get("git")
    if not isinstance(git_config, dict):
        git_config = {}
        config["git"] = git_config
    git_config["identity"] = dict(identity)
    config_text = json.dumps(config, ensure_ascii=False, indent=2) + "\n"

    existing_profile = (
        profile_path.read_text(encoding="utf-8")
        if profile_path.is_file()
        else render_content(PROFILE_FILES[".moduflow/project-profile.md"])
    )
    profile_text = _project_profile_with_identity(existing_profile, identity)

    previous_config = config_path.read_text(encoding="utf-8") if config_path.is_file() else None
    previous_profile = profile_path.read_text(encoding="utf-8") if profile_path.is_file() else None
    config_path.parent.mkdir(parents=True, exist_ok=True)
    config_path.write_text(config_text, encoding="utf-8")
    profile_path.write_text(profile_text, encoding="utf-8")
    return {
        "schema": "moduflow.repository-identity-write.v1",
        "written": previous_config != config_text or previous_profile != profile_text,
        "config_path": str(config_path),
        "profile_path": str(profile_path),
        "identity": identity,
    }


def main():
    parser = argparse.ArgumentParser(description="Plan or create ModuFlow project profile metadata.")
    parser.add_argument("project_path", nargs="?", default=".")
    parser.add_argument("--write", action="store_true", help="Create missing profile metadata files.")
    parser.add_argument("--canonical-repository")
    parser.add_argument("--provider", choices=sorted(ALLOWED_PROVIDERS))
    parser.add_argument("--remote-name-hint")
    parser.add_argument("--base-branch")
    parser.add_argument("--lifecycle", choices=sorted(ALLOWED_LIFECYCLES))
    parser.add_argument("--local-only", action="store_true")
    args = parser.parse_args()

    plan = build_profile_plan(args.project_path, dry_run=not args.write)
    proposal = build_repository_identity_proposal(
        args.project_path,
        canonical_repository=args.canonical_repository,
        provider=args.provider,
        remote_name_hint=args.remote_name_hint,
        base_branch=args.base_branch,
        lifecycle=args.lifecycle,
        local_only=args.local_only,
    )
    plan["repository_identity"] = proposal
    if args.write:
        plan = apply_profile_plan(plan)
        if proposal["proposed_identity"] is not None and (
            args.canonical_repository is not None or args.local_only
        ):
            plan["repository_identity_write"] = apply_repository_identity_proposal(
                args.project_path,
                proposal,
            )
    print(json.dumps(plan, ensure_ascii=False, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Canonical repository identity parsing and normalization for ModuFlow."""

import argparse
import json
import re
from pathlib import Path
from urllib.parse import urlsplit


ALLOWED_MODES = {"remote", "local_only"}
ALLOWED_PROVIDERS = {"github", "generic"}
ALLOWED_LIFECYCLES = {"active", "read_only", "archived"}
SCP_URL_RE = re.compile(r"^(?:[^@/:]+@)?(?P<host>[^/:]+):(?P<path>.+)$")
GITHUB_ARTIFACT_URL_RE = re.compile(
    r"https://github\.com/[A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+(?:/[^\s<>()`\]]*)?"
)
OPERATION_CAPABILITIES = {
    "doctor": "read",
    "status": "read",
    "validate": "read",
    "execute": "execute",
    "commit": "commit",
    "github_api_commit": "github_write",
    "push": "push",
    "github_issue": "github_write",
    "pr": "github_write",
    "release": "release",
}
MISMATCH_REASONS = {
    "git_root_mismatch",
    "fetch_remote_mismatch",
    "push_remote_mismatch",
    "provider_repository_mismatch",
    "provider_default_branch_mismatch",
    "provider_repository_is_fork",
    "provider_archive_state_mismatch",
    "artifact_write_repository_mismatch",
}


class IdentityConfigError(ValueError):
    """Raised when repository identity input cannot be safely normalized."""


def _reason(code, message):
    return {"code": code, "message": message}


def _invalid_url(message):
    raise IdentityConfigError(message)


def _split_host_path(value):
    text = str(value or "").strip()
    if not text or text.startswith(("/", "./", "../", "~")):
        _invalid_url("Repository URL must be an absolute network repository URL.")

    if "://" in text:
        parsed = urlsplit(text)
        if parsed.scheme not in {"https", "ssh", "git"}:
            _invalid_url("Repository URL uses an unsupported scheme.")
        if not parsed.hostname:
            _invalid_url("Repository URL is missing a host.")
        try:
            port = parsed.port
        except ValueError:
            _invalid_url("Repository URL has an invalid port.")
        default_port = (
            (parsed.scheme == "https" and port == 443)
            or (parsed.scheme == "ssh" and port == 22)
            or port is None
        )
        host = parsed.hostname.lower()
        if not default_port:
            host = f"{host}:{port}"
        path = parsed.path
    else:
        scp_match = SCP_URL_RE.match(text)
        if scp_match:
            host = scp_match.group("host").lower()
            path = scp_match.group("path")
        else:
            host, separator, path = text.partition("/")
            if not separator or not host or not path or "." not in host:
                _invalid_url("Repository identity must contain a host and repository path.")
            host = host.lower()

    normalized_path = path.strip("/")
    if normalized_path.endswith(".git"):
        normalized_path = normalized_path[:-4]
    if not normalized_path or normalized_path.startswith(("./", "../")):
        _invalid_url("Repository URL is missing a valid repository path.")
    return host, normalized_path


def normalize_git_url(value, provider):
    """Return a credential-free comparable host/path repository identity."""
    if provider not in ALLOWED_PROVIDERS:
        raise IdentityConfigError("Repository provider must be github or generic.")

    host, path = _split_host_path(value)
    parts = path.split("/")

    if provider == "github":
        if host != "github.com":
            raise IdentityConfigError("GitHub repository identity must use github.com.")
        if len(parts) != 2 or not all(parts):
            raise IdentityConfigError("GitHub repository identity must be owner/repository.")
        path = "/".join(part.lower() for part in parts)

    return f"{host}/{path}"


def repository_from_github_artifact_url(value):
    """Resolve the repository identity from a GitHub issue/PR/release URL."""
    parsed = urlsplit(str(value or "").strip())
    if parsed.scheme != "https" or (parsed.hostname or "").lower() != "github.com":
        raise IdentityConfigError("GitHub artifact URL must use https://github.com.")
    parts = [part for part in parsed.path.split("/") if part]
    if len(parts) < 4 or parts[2] not in {"issues", "pull", "releases"}:
        raise IdentityConfigError("GitHub artifact URL is not an issue, pull, or release URL.")
    return normalize_git_url(f"github.com/{parts[0]}/{parts[1]}", "github")


def _repository_artifact_paths(root):
    root = Path(root)
    paths = []
    issues_dir = root / "issues"
    if issues_dir.is_dir():
        paths.extend(sorted(issues_dir.glob("*.md")))
    specs_dir = root / "specs"
    if specs_dir.is_dir():
        for name in ["spec.md", "plan.md", "status.md", "review.md", "pr.md", "release.md"]:
            paths.extend(sorted(specs_dir.glob(f"*/{name}")))
    for relative in ["status.md", "workspace/status.md"]:
        target = root / relative
        if target.is_file():
            paths.append(target)
    return sorted(set(paths))


def audit_repository_links(root, canonical_repository=None):
    """Classify GitHub repository links in Git-native execution artifacts."""
    root = Path(root).resolve()
    if canonical_repository is None:
        config = load_repository_identity(root)
        identity = config.get("identity") or {}
        canonical_repository = identity.get("canonical_repository")
    if not canonical_repository:
        return []

    findings = []
    for path in _repository_artifact_paths(root):
        heading = ""
        for line_number, line in enumerate(path.read_text(encoding="utf-8").splitlines(), 1):
            if line.startswith("## "):
                heading = line[3:].strip()
            for match in GITHUB_ARTIFACT_URL_RE.finditer(line):
                url = match.group(0).rstrip(".,;:")
                try:
                    repository = repository_from_github_artifact_url(url)
                except IdentityConfigError:
                    parts = urlsplit(url).path.strip("/").split("/")
                    if len(parts) < 2:
                        continue
                    repository = normalize_git_url(
                        f"github.com/{parts[0]}/{parts[1]}",
                        "github",
                    )
                context = f"{heading} {line}".lower()
                if repository == canonical_repository:
                    classification = "canonical"
                    role = "canonical"
                elif "mirror" in context:
                    classification = "mirror"
                    role = "mirror"
                elif any(token in context for token in ["reference", "benchmark", "example"]):
                    classification = "reference"
                    role = "reference"
                else:
                    classification = "mismatch"
                    role = None
                write_handoff = path.name in {"pr.md", "release.md"} or bool(
                    re.search(r"(?:github|target)\s*(?:pr|issue|release)?\s*:", line, re.I)
                )
                findings.append(
                    {
                        "artifact": str(path.relative_to(root)),
                        "line": line_number,
                        "url": url,
                        "repository": repository,
                        "role": role,
                        "classification": classification,
                        "write_handoff": write_handoff,
                    }
                )
    return findings


def _unconfigured(message="Canonical repository identity is not configured."):
    return {
        "schema": "moduflow.repository-identity-config.v1",
        "configured": False,
        "identity": None,
        "reasons": [_reason("canonical_identity_missing", message)],
    }


def _invalid_config(message):
    return {
        "schema": "moduflow.repository-identity-config.v1",
        "configured": False,
        "identity": None,
        "reasons": [_reason("canonical_identity_invalid", message)],
    }


def load_repository_identity(root):
    """Load and validate `.moduflow/config.json` canonical Git identity."""
    config_path = Path(root).resolve() / ".moduflow" / "config.json"
    if not config_path.is_file():
        return _unconfigured()

    try:
        config = json.loads(config_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return _invalid_config(".moduflow/config.json is unreadable or invalid JSON.")

    git_config = config.get("git")
    identity = git_config.get("identity") if isinstance(git_config, dict) else None
    if not isinstance(identity, dict):
        return _unconfigured()

    mode = identity.get("mode")
    provider = identity.get("provider")
    base_branch = identity.get("base_branch")
    lifecycle = identity.get("lifecycle")

    if mode not in ALLOWED_MODES:
        return _invalid_config("git.identity.mode must be remote or local_only.")
    if provider not in ALLOWED_PROVIDERS:
        return _invalid_config("git.identity.provider must be github or generic.")
    if not isinstance(base_branch, str) or not base_branch.strip():
        return _invalid_config("git.identity.base_branch must be a non-empty string.")
    if lifecycle not in ALLOWED_LIFECYCLES:
        return _invalid_config(
            "git.identity.lifecycle must be active, read_only, or archived."
        )

    normalized = {
        "mode": mode,
        "provider": provider,
        "base_branch": base_branch.strip(),
        "lifecycle": lifecycle,
    }

    if mode == "remote":
        canonical_repository = identity.get("canonical_repository")
        remote_name_hint = identity.get("remote_name_hint")
        if not isinstance(canonical_repository, str) or not canonical_repository.strip():
            return _invalid_config(
                "git.identity.canonical_repository is required in remote mode."
            )
        if not isinstance(remote_name_hint, str) or not remote_name_hint.strip():
            return _invalid_config(
                "git.identity.remote_name_hint is required in remote mode."
            )
        try:
            normalized["canonical_repository"] = normalize_git_url(
                canonical_repository,
                provider,
            )
        except IdentityConfigError as exc:
            return _invalid_config(f"git.identity.canonical_repository is invalid: {exc}")
        normalized["remote_name_hint"] = remote_name_hint.strip()

    return {
        "schema": "moduflow.repository-identity-config.v1",
        "configured": True,
        "identity": normalized,
        "reasons": [],
    }


def _default_runner(args, cwd):
    try:
        from scripts.project_sync import run_command
    except ModuleNotFoundError:
        from project_sync import run_command

    return run_command(args, cwd)


def _run(runner, args, root):
    try:
        return runner(args, root)
    except (OSError, RuntimeError) as exc:
        return type(
            "CommandFailure",
            (),
            {"returncode": 1, "stdout": "", "stderr": type(exc).__name__},
        )()


def _default_github_provider_check(canonical_repository, root, runner):
    owner_repo = canonical_repository.split("/", 1)[1]
    result = _run(
        runner,
        [
            "gh",
            "repo",
            "view",
            owner_repo,
            "--json",
            "nameWithOwner,defaultBranchRef,isArchived,isFork",
        ],
        root,
    )
    if result.returncode != 0:
        return {
            "ok": False,
            "reason": "provider_unavailable",
            "detail": f"gh repo view failed with exit code {result.returncode}.",
        }
    try:
        payload = json.loads(result.stdout or "{}")
        default_branch = payload.get("defaultBranchRef")
        if isinstance(default_branch, dict):
            default_branch = default_branch.get("name")
        repository = normalize_git_url(
            f"github.com/{payload.get('nameWithOwner', '')}",
            "github",
        )
    except (json.JSONDecodeError, IdentityConfigError, TypeError):
        return {
            "ok": False,
            "reason": "provider_unavailable",
            "detail": "gh repo view returned invalid repository evidence.",
        }
    return {
        "ok": True,
        "repository": repository,
        "default_branch": default_branch,
        "archived": bool(payload.get("isArchived")),
        "fork": bool(payload.get("isFork")),
    }


def _output_lines(result):
    if result.returncode != 0:
        return []
    return [line.strip() for line in (result.stdout or "").splitlines() if line.strip()]


def _normalized_urls(values, provider, invalid_code, reasons):
    normalized = []
    for value in values:
        try:
            normalized.append(normalize_git_url(value, provider))
        except IdentityConfigError:
            reasons.append(
                _reason(invalid_code, "Observed repository URL could not be safely normalized.")
            )
    return normalized


def _has_reason(reasons, code):
    return any(reason["code"] == code for reason in reasons)


def _base_ref(root, runner, identity):
    base_branch = identity["base_branch"]
    candidates = []
    if identity["mode"] == "remote":
        candidates.append(
            f"refs/remotes/{identity['remote_name_hint']}/{base_branch}"
        )
    candidates.append(f"refs/heads/{base_branch}")
    for candidate in candidates:
        result = _run(
            runner,
            ["git", "show-ref", "--verify", "--quiet", candidate],
            root,
        )
        if result.returncode == 0:
            return candidate
    return None


def _unconfigured_result(root, config_result):
    return {
        "schema": "moduflow.repository-identity.v1",
        "status": "unconfigured",
        "expected": {},
        "observed": {
            "git_root": None,
            "fetch_repositories": [],
            "push_repositories": [],
            "current_branch": None,
            "base_ref": None,
            "provider_repository": None,
            "provider_default_branch": None,
            "provider_archived": None,
            "provider_fork": None,
            "artifact_link_mismatches": [],
        },
        "capabilities": {
            "read": True,
            "execute": False,
            "commit": False,
            "push": False,
            "github_write": False,
            "release": False,
        },
        "reasons": list(config_result["reasons"]),
        "project_root": str(Path(root).resolve()),
    }


def inspect_repository_identity(root, runner=None, provider_check=None):
    """Collect canonical, Git, and provider evidence without performing writes."""
    root = Path(root).resolve()
    runner = runner or _default_runner
    config_result = load_repository_identity(root)
    if not config_result["configured"]:
        return _unconfigured_result(root, config_result)

    identity = config_result["identity"]
    expected = {
        "mode": identity["mode"],
        "provider": identity["provider"],
        "base_branch": identity["base_branch"],
        "lifecycle": identity["lifecycle"],
    }
    if identity["mode"] == "remote":
        expected["repository"] = identity["canonical_repository"]
        expected["remote_name_hint"] = identity["remote_name_hint"]

    reasons = []
    observed = {
        "git_root": None,
        "fetch_repositories": [],
        "push_repositories": [],
        "current_branch": None,
        "base_ref": None,
        "provider_repository": None,
        "provider_default_branch": None,
        "provider_archived": None,
        "provider_fork": None,
        "artifact_link_mismatches": [],
    }

    git_root_result = _run(runner, ["git", "rev-parse", "--show-toplevel"], root)
    if git_root_result.returncode == 0 and (git_root_result.stdout or "").strip():
        observed["git_root"] = (git_root_result.stdout or "").strip()
        if Path(observed["git_root"]).resolve() != root:
            reasons.append(
                _reason(
                    "git_root_mismatch",
                    "Observed Git root does not match the requested project root.",
                )
            )
    else:
        reasons.append(_reason("git_root_unavailable", "Git repository root is unavailable."))

    branch_result = _run(runner, ["git", "rev-parse", "--abbrev-ref", "HEAD"], root)
    if branch_result.returncode == 0:
        observed["current_branch"] = (branch_result.stdout or "").strip() or None

    if observed["git_root"]:
        observed["base_ref"] = _base_ref(root, runner, identity)
        if not observed["base_ref"]:
            reasons.append(
                _reason(
                    "base_branch_missing",
                    "Configured base branch does not exist in local or remote refs.",
                )
            )

    if identity["mode"] == "remote":
        remote_name = identity["remote_name_hint"]
        fetch_result = _run(
            runner,
            ["git", "remote", "get-url", "--all", remote_name],
            root,
        )
        fetch_values = _output_lines(fetch_result)
        if not fetch_values:
            reasons.append(
                _reason("fetch_remote_missing", "Configured fetch remote is unavailable.")
            )
        observed["fetch_repositories"] = _normalized_urls(
            fetch_values,
            identity["provider"],
            "fetch_remote_invalid",
            reasons,
        )
        if observed["fetch_repositories"] and any(
            repository != identity["canonical_repository"]
            for repository in observed["fetch_repositories"]
        ):
            reasons.append(
                _reason(
                    "fetch_remote_mismatch",
                    "Observed fetch repository does not match the canonical repository.",
                )
            )

        push_result = _run(
            runner,
            ["git", "remote", "get-url", "--push", "--all", remote_name],
            root,
        )
        push_values = _output_lines(push_result)
        if not push_values:
            reasons.append(
                _reason("push_remote_missing", "Configured push remote is unavailable.")
            )
        observed["push_repositories"] = _normalized_urls(
            push_values,
            identity["provider"],
            "push_remote_invalid",
            reasons,
        )
        if observed["push_repositories"] and any(
            repository != identity["canonical_repository"]
            for repository in observed["push_repositories"]
        ):
            reasons.append(
                _reason(
                    "push_remote_mismatch",
                    "Observed push repository does not match the canonical repository.",
                )
            )

        if identity["provider"] == "github":
            check = provider_check or _default_github_provider_check
            provider = check(identity["canonical_repository"], root, runner)
            if not provider.get("ok"):
                reasons.append(
                    _reason(
                        provider.get("reason", "provider_unavailable"),
                        provider.get("detail", "Repository provider evidence is unavailable."),
                    )
                )
            else:
                observed["provider_repository"] = provider.get("repository")
                observed["provider_default_branch"] = provider.get("default_branch")
                observed["provider_archived"] = bool(provider.get("archived"))
                observed["provider_fork"] = bool(provider.get("fork"))
                if observed["provider_repository"] != identity["canonical_repository"]:
                    reasons.append(
                        _reason(
                            "provider_repository_mismatch",
                            "Provider repository does not match the canonical repository.",
                        )
                    )
                if observed["provider_default_branch"] != identity["base_branch"]:
                    reasons.append(
                        _reason(
                            "provider_default_branch_mismatch",
                            "Provider default branch does not match the configured base branch.",
                        )
                    )
                if observed["provider_archived"] and identity["lifecycle"] != "archived":
                    reasons.append(
                        _reason(
                            "provider_archive_state_mismatch",
                            "Provider reports the repository as archived.",
                        )
                    )
                if observed["provider_fork"]:
                    reasons.append(
                        _reason(
                            "provider_repository_is_fork",
                            "Provider reports the canonical repository as a fork.",
                        )
                    )

    if identity["lifecycle"] == "read_only":
        reasons.append(_reason("repository_read_only", "Repository lifecycle is read_only."))
    elif identity["lifecycle"] == "archived":
        reasons.append(_reason("repository_archived", "Repository lifecycle is archived."))

    if identity["mode"] == "remote":
        link_findings = audit_repository_links(root, identity["canonical_repository"])
        observed["artifact_link_mismatches"] = [
            finding for finding in link_findings if finding["classification"] == "mismatch"
        ]
        if any(
            finding["write_handoff"]
            for finding in observed["artifact_link_mismatches"]
        ):
            reasons.append(
                _reason(
                    "artifact_write_repository_mismatch",
                    "A write-handoff artifact targets a non-canonical repository.",
                )
            )
    reason_code_set = {reason["code"] for reason in reasons}
    active = identity["lifecycle"] == "active"
    local_base_ok = bool(
        observed["git_root"]
        and observed["base_ref"]
        and "git_root_mismatch" not in reason_code_set
    )
    fetch_ok = identity["mode"] == "local_only" or not reason_code_set.intersection(
        {"fetch_remote_missing", "fetch_remote_invalid", "fetch_remote_mismatch"}
    )
    push_ok = identity["mode"] == "remote" and not reason_code_set.intersection(
        {"push_remote_missing", "push_remote_invalid", "push_remote_mismatch"}
    )
    provider_ok = identity["provider"] != "github" or not reason_code_set.intersection(
        {
            "provider_unavailable",
            "provider_repository_mismatch",
            "provider_default_branch_mismatch",
            "provider_archive_state_mismatch",
            "provider_repository_is_fork",
            "artifact_write_repository_mismatch",
        }
    )
    execute_ok = active and local_base_ok and fetch_ok
    if identity["mode"] == "local_only":
        commit_ok = execute_ok
        push_capability = False
        github_write = False
        release = False
    else:
        commit_ok = execute_ok and push_ok
        push_capability = commit_ok
        github_write = (
            push_capability and identity["provider"] == "github" and provider_ok
        )
        release = github_write

    if identity["lifecycle"] == "read_only":
        status = "read_only"
    elif identity["lifecycle"] == "archived":
        status = "archived"
    elif reason_code_set.intersection(MISMATCH_REASONS):
        status = "mismatch"
    elif reasons:
        status = "unverifiable"
    elif identity["mode"] == "local_only":
        status = "local_only"
    else:
        status = "match"

    return {
        "schema": "moduflow.repository-identity.v1",
        "status": status,
        "expected": expected,
        "observed": observed,
        "capabilities": {
            "read": True,
            "execute": execute_ok,
            "commit": commit_ok,
            "push": push_capability,
            "github_write": github_write,
            "release": release,
        },
        "reasons": reasons,
        "project_root": str(root),
    }


def operation_decision(result, operation):
    """Evaluate one operation against a fresh repository identity result."""
    capability = OPERATION_CAPABILITIES.get(operation)
    if capability is None:
        return {
            "schema": "moduflow.repository-operation-decision.v1",
            "operation": operation,
            "capability": None,
            "allowed": False,
            "reasons": [
                _reason("unsupported_operation", "Repository operation is not supported.")
            ],
            "identity": result,
        }

    allowed = bool(result.get("capabilities", {}).get(capability, False))
    reasons = [] if allowed else list(result.get("reasons", []))
    if not allowed and not reasons:
        reasons.append(
            _reason(
                "capability_not_available",
                f"Repository capability '{capability}' is not available.",
            )
        )
    return {
        "schema": "moduflow.repository-operation-decision.v1",
        "operation": operation,
        "capability": capability,
        "allowed": allowed,
        "reasons": reasons,
        "identity": result,
    }


def main():
    parser = argparse.ArgumentParser(
        description="Inspect canonical repository identity and evaluate one operation."
    )
    parser.add_argument("project_path", nargs="?", default=".")
    parser.add_argument("--operation", choices=sorted(OPERATION_CAPABILITIES))
    parser.add_argument(
        "--provider-check",
        action="store_true",
        help="Request explicit provider evidence (provider-backed operations already require it).",
    )
    args = parser.parse_args()

    result = inspect_repository_identity(args.project_path)
    if args.operation:
        decision = operation_decision(result, args.operation)
        print(json.dumps(decision, ensure_ascii=False, indent=2))
        return 0 if decision["allowed"] else 3

    print(json.dumps(result, ensure_ascii=False, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
import argparse
import json
import os
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path

if __package__ in (None, ""):
    # Allow `python3 scripts/project_sync.py` (documented CLI usage) to resolve
    # the cross-script import below, in addition to `from scripts import project_sync`.
    sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from scripts.project_lifecycle import _issue_status
from scripts.project_repository_identity import inspect_repository_identity

FETCH_TIMEOUT_SECONDS = 5


@dataclass
class CommandResult:
    returncode: int
    stdout: str
    stderr: str


def _no_prompt_env():
    env = dict(os.environ)
    env["GIT_TERMINAL_PROMPT"] = "0"
    return env


def run_command(args, cwd, timeout=None):
    try:
        result = subprocess.run(
            args,
            cwd=str(cwd),
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
            timeout=timeout,
            env=_no_prompt_env(),
        )
    except FileNotFoundError as exc:
        return CommandResult(127, "", str(exc))
    except subprocess.TimeoutExpired:
        suffix = f" after {timeout}s" if timeout else ""
        return CommandResult(124, "", f"git command timed out{suffix}")
    return CommandResult(result.returncode, result.stdout, result.stderr)


def _run(runner, args, cwd, timeout=None):
    if timeout is not None:
        return runner(args, cwd, timeout=timeout)
    return runner(args, cwd)


def _stdout(result):
    return (result.stdout or "").strip()


def _parse_rev_counts(text):
    parts = text.replace("\t", " ").split()
    if len(parts) < 2:
        return 0, 0
    try:
        return int(parts[0]), int(parts[1])
    except ValueError:
        return 0, 0


def _current_branch_vv_line(branch_vv, branch):
    for line in branch_vv.splitlines():
        stripped = line.strip()
        if stripped.startswith("* "):
            return stripped
        if branch and stripped.startswith(branch + " "):
            return stripped
    return ""


def _default_remote_branch(runner, cwd, repository_identity=None):
    expected = (repository_identity or {}).get("expected", {})
    remote_name = expected.get("remote_name_hint")
    base_branch = expected.get("base_branch")
    if remote_name and base_branch:
        return f"{remote_name}/{base_branch}"
    result = _run(runner, ["git", "symbolic-ref", "refs/remotes/origin/HEAD"], cwd)
    if result.returncode == 0:
        ref = _stdout(result)
        prefix = "refs/remotes/"
        if ref.startswith(prefix):
            return ref[len(prefix) :]
    return "origin/main"


def _issue_id(path):
    if not path.startswith("issues/") or not path.endswith(".md"):
        return None
    name = path[len("issues/") : -len(".md")]
    return name or None


def _issue_ids_from_paths(paths_text):
    issue_ids = []
    for line in paths_text.splitlines():
        issue_id = _issue_id(line.strip())
        if issue_id:
            issue_ids.append(issue_id)
    return sorted(set(issue_ids))


def _list_remote_branches(runner, cwd, default_remote):
    result = _run(runner, ["git", "for-each-ref", "--format=%(refname:short)", "refs/remotes"], cwd)
    if result.returncode != 0:
        return []
    branches = []
    for line in _stdout(result).splitlines():
        line = line.strip()
        if not line or line.endswith("/HEAD") or line == default_remote:
            continue
        branches.append(line)
    return branches


def _issue_ids_in_ref(runner, cwd, ref):
    result = _run(runner, ["git", "ls-tree", "-r", "--name-only", ref, "issues"], cwd)
    if result.returncode != 0:
        return []
    return _issue_ids_from_paths(result.stdout)


def _status_at_ref(runner, cwd, ref, issue_id):
    result = _run(runner, ["git", "show", f"{ref}:issues/{issue_id}.md"], cwd)
    if result.returncode != 0:
        return None
    return _issue_status(result.stdout)


def find_unmerged_branch_work(runner, cwd, default_remote):
    findings = []
    for branch in _list_remote_branches(runner, cwd, default_remote):
        counts = _run(
            runner,
            ["git", "rev-list", "--left-right", "--count", f"{default_remote}...{branch}"],
            cwd,
        )
        if counts.returncode != 0:
            continue
        _, ahead = _parse_rev_counts(counts.stdout)
        if not ahead:
            continue

        done_issue_ids = []
        for issue_id in _issue_ids_in_ref(runner, cwd, branch):
            if _status_at_ref(runner, cwd, branch, issue_id) != "done":
                continue
            if _status_at_ref(runner, cwd, default_remote, issue_id) != "done":
                done_issue_ids.append(issue_id)

        if done_issue_ids:
            findings.append(
                {
                    "branch": branch,
                    "ahead": ahead,
                    "done_issue_ids": sorted(done_issue_ids),
                }
            )
    return findings


def inspect_repo_sync(path=".", runner=None, fetch=True):
    cwd = Path(path).resolve()
    runner = runner or run_command
    is_repo = _run(runner, ["git", "rev-parse", "--is-inside-work-tree"], cwd)
    if is_repo.returncode != 0:
        return {
            "schema": "moduflow.repo-sync.v1",
            "project_root": str(cwd),
            "is_repo": False,
            "recommendations": ["Choose a Git repository before running repo sync preflight."],
            "errors": [_stdout(is_repo) or (is_repo.stderr or "").strip()],
        }

    repository_identity = inspect_repository_identity(cwd, runner=runner)

    fetch_mode = "auto"
    if fetch:
        try:
            fetch_result = _run(runner, ["git", "fetch", "--quiet"], cwd, timeout=FETCH_TIMEOUT_SECONDS)
        except subprocess.TimeoutExpired:
            fetch_result = CommandResult(124, "", f"git fetch timed out after {FETCH_TIMEOUT_SECONDS}s")
        fetched = fetch_result.returncode == 0
        fetch_warning = None
        if not fetched:
            stderr = (fetch_result.stderr or "").strip()
            fetch_warning = f"git fetch failed: {stderr}" if stderr else "git fetch failed"
    else:
        fetched = False
        fetch_warning = "git fetch skipped by request"
        fetch_mode = "skipped"

    branch_result = _run(runner, ["git", "rev-parse", "--abbrev-ref", "HEAD"], cwd)
    branch = _stdout(branch_result) if branch_result.returncode == 0 else None

    upstream_result = _run(
        runner,
        ["git", "rev-parse", "--abbrev-ref", "--symbolic-full-name", "@{u}"],
        cwd,
    )
    upstream = _stdout(upstream_result) if upstream_result.returncode == 0 else None

    branch_vv_result = _run(runner, ["git", "branch", "-vv"], cwd)
    branch_vv = _stdout(branch_vv_result) if branch_vv_result.returncode == 0 else ""
    branch_line = _current_branch_vv_line(branch_vv, branch)
    upstream_gone = ": gone]" in branch_line or "[gone]" in branch_line

    default_remote = _default_remote_branch(runner, cwd, repository_identity)

    upstream_ahead = 0
    upstream_behind = 0
    if upstream:
        counts = _run(runner, ["git", "rev-list", "--left-right", "--count", f"HEAD...{upstream}"], cwd)
        if counts.returncode == 0:
            upstream_ahead, upstream_behind = _parse_rev_counts(counts.stdout)

    default_remote_behind = 0
    default_remote_ahead = 0
    if default_remote:
        counts = _run(
            runner,
            ["git", "rev-list", "--left-right", "--count", f"HEAD...{default_remote}"],
            cwd,
        )
        if counts.returncode == 0:
            default_remote_behind, default_remote_ahead = _parse_rev_counts(counts.stdout)

    status = _run(runner, ["git", "status", "--porcelain"], cwd)
    dirty = bool(_stdout(status)) if status.returncode == 0 else None

    remote_issues = _run(runner, ["git", "ls-tree", "-r", "--name-only", default_remote, "issues"], cwd)
    local_issues = _run(runner, ["git", "ls-files", "issues"], cwd)
    remote_issue_ids = _issue_ids_from_paths(remote_issues.stdout if remote_issues.returncode == 0 else "")
    local_issue_ids = _issue_ids_from_paths(local_issues.stdout if local_issues.returncode == 0 else "")
    remote_only_issue_ids = sorted(set(remote_issue_ids) - set(local_issue_ids))

    unmerged_branch_work = find_unmerged_branch_work(runner, cwd, default_remote)

    result = {
        "schema": "moduflow.repo-sync.v1",
        "project_root": str(cwd),
        "is_repo": True,
        "fetch_mode": fetch_mode,
        "fetched": fetched,
        "fetch_warning": fetch_warning,
        "branch": branch,
        "upstream": upstream,
        "upstream_gone": upstream_gone,
        "upstream_ahead": upstream_ahead,
        "upstream_behind": upstream_behind,
        "default_remote": default_remote,
        "default_remote_behind": default_remote_behind,
        "default_remote_ahead": default_remote_ahead,
        "dirty": dirty,
        "remote_only_issue_ids": remote_only_issue_ids,
        "unmerged_branch_work": unmerged_branch_work,
        "repository_identity": repository_identity,
        "mode_note": "git-files mode stores ModuFlow issues in repo files such as issues/*.md; GitHub Issues objects are optional mirrors.",
    }
    result["recommendations"] = format_recommendations(result)
    return result


def format_recommendations(result):
    recommendations = []
    if not result.get("is_repo"):
        return result.get("recommendations", [])
    if result.get("fetched") is False and result.get("fetch_mode") != "skipped":
        recommendations.append(
            f"Could not fetch from the remote ({result.get('fetch_warning')}); freshness numbers below reflect the last local fetch, not the current remote."
        )
    if not result.get("upstream"):
        recommendations.append(
            f"Current branch {result.get('branch') or '(unknown)'} has no upstream; compare against the default remote before trusting local artifact state."
        )
    if result.get("upstream_gone"):
        recommendations.append(
            "Current upstream branch is gone; switch to the default branch or choose an active work branch before reading local artifacts."
        )
    if result.get("dirty"):
        recommendations.append(
            "The worktree has local changes; do not auto-fast-forward until those changes are reviewed."
        )
    default_remote_ahead = result.get("default_remote_ahead") or 0
    if default_remote_ahead:
        if result.get("dirty"):
            recommendations.append(
                f"{result.get('default_remote')} is {default_remote_ahead} commits ahead, but the worktree is dirty; review local changes before fast-forward."
            )
        else:
            recommendations.append(
                f"{result.get('default_remote')} is {default_remote_ahead} commits ahead; fast-forward the local branch before status if you want the latest Git-file artifacts."
            )
    if result.get("remote_only_issue_ids"):
        sample = ", ".join(result["remote_only_issue_ids"][:5])
        recommendations.append(
            f"{result.get('default_remote')} has issue files missing locally: {sample}. Refresh the checkout before concluding GitHub work is missing."
        )
    for finding in result.get("unmerged_branch_work") or []:
        ids = ", ".join(finding["done_issue_ids"])
        recommendations.append(
            f"{finding['branch']} is {finding['ahead']} commits ahead of {result.get('default_remote')} and has done issue(s) not done there: {ids}."
        )
    if not recommendations:
        recommendations.append("Repo sync preflight is clean.")
    return recommendations


def main():
    parser = argparse.ArgumentParser(description="Inspect ModuFlow repo sync freshness.")
    parser.add_argument("project_path", nargs="?", default=".")
    parser.add_argument(
        "--no-fetch",
        action="store_true",
        help="Skip the internal git fetch. Use after running a top-level git fetch in approval-sensitive hosts.",
    )
    args = parser.parse_args()
    print(json.dumps(inspect_repo_sync(args.project_path, fetch=not args.no_fetch), ensure_ascii=False, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
